#!/usr/bin/env python3# -*- coding: utf-8 -*-""""""import pandas as pdimport sysfrom collections import defaultdictfrom datetime import datetimeclass Item:    def __init__(self, length: float, width: float, height: float, weight: float, customerId:int, order_id:int, item_id):        self.length     = length        self.width      = width        self.height     = height        self.weight     = weight        self.customerId = customerId        self.order_id   = order_id        self.item_id    = item_id                    def __repr__(self):        return (            f"{self.length} {self.width} {self.height} {self.weight} {self.item_id}"        )class Dist:    def __init__(self, custI:int, custJ:int, dist:float):        self.custI = custI        self.custJ = custJ        self.dist  = dist            def __repr__(self):        return (f"{self.custI} {self.custJ} {self.dist}")def main():        if len(sys.argv) != 2:        print("Error, python3 ", sys.argv[0], " S10_240T_items.csv\n")        return        itemsStr = sys.argv[1]    instName = itemsStr.replace("_items.csv", "")        today_str = datetime.now().strftime("%d/%m/%y %H:%M:%S")    print("#Date:", today_str)    print("#Instance Name:", instName)        #print(itemsStr, "\n")    solItemsStr = instName + "_sol_items.csv"    solItemsDf  = pd.read_csv(solItemsStr)        numTrucks = solItemsDf["truck_id"].max()            #print(solItemsDf)    distancesDf = pd.read_csv("distances.csv")    itemsDf     = pd.read_csv(itemsStr)        #print(itemsDf)        multimapCustomerItems = defaultdict(list)    numItems = 0    customers = set()    vetItens = []    #vetOrderId = []    for itemLine in itemsDf.itertuples(index=False):        numItems = numItems + 1        item = Item(float(itemLine.length), float(itemLine.width), float(itemLine.height),                     float(itemLine.weight), itemLine.delivery_address_id, itemLine.order_id, itemLine.item_id)        #vetOrderId.append(itemLine.order_id)        multimapCustomerItems[itemLine.delivery_address_id].append(item)        #vetItens.append(item)                if itemLine.delivery_address_id is not customers:            customers.add(int(itemLine.delivery_address_id))            #print(multimapCustomerItems)    #customers = [i for i in customers]    #customers.sort()    #print(customers)        # Add the central deposit    customers.add(int(1000))    vetCustomers = [i for i in customers]    vetCustomers.sort()    #print(vetCustomers)        customersConv = {}    i = 0    for cust in vetCustomers:        customersConv[cust] = i        i = i + 1        vetDist = []        #print(customersConv)        for distLine in distancesDf.itertuples(index=False):        custI = int(distLine.id_1)        custJ = int(distLine.id_2)        dist  = float(distLine.distance)                #print("Checking: ", custI, custJ)                if custI in customers and custJ in customers:            vetDist.append(Dist(customersConv[custI], customersConv[custJ], dist))    #print(vetDist)        print(len(vetCustomers), " # Customers + deposit")        print("#Trailer size (length, width, height) in millimeters")    print("13500 2450 2700")    print(numTrucks, " #Number of Trucks")    print("24000 #Maximum truck payload")    print(numItems, "#Number of Itms")        print("#Distances - Simetric")    print(len(vetDist), " #Number of arcs")    for dist in vetDist:        print(dist)        print("#Itens; custId numOfItems <L W H Wt item_id>")    for customer in vetCustomers:        if customer == 1000:            continue        print(customersConv[customer], len(multimapCustomerItems[customer]), end=" ")        for item in multimapCustomerItems[customer]:            print(item, end=" ")            vetItens.append(item)        print()            print("#Order_Id Item_ID")    for item in vetItens:        print(item.order_id, " ", item.item_id)            print("#customer_id customer")    for customer in vetCustomers:        print(customer, " ", customersConv[customer])    if __name__ == "__main__":    main()